+export type DurationHistory = Record<string, DurationObservation[]>
+
+function observations(value: unknown): DurationObservation[] | null {
+  const values = typeof value === 'number'
+    ? [{ duration: value, recordedAt: 0 }]
+    : value && typeof value === 'object' && 'observations' in value
+      ? (value as { observations: unknown }).observations
+      : value && typeof value === 'object' && 'duration' in value
+        ? [value]
+        : null
+  if (!Array.isArray(values) || values.some(item => !item || typeof item !== 'object' || !Number.isFinite((item as DurationObservation).duration) || !Number.isFinite((item as DurationObservation).recordedAt))) return null
+  return values as DurationObservation[]
+}
+
+export async function readDurationHistory(root: string, path: string, ttl: number): Promise<DurationHistory | null> {
+  try {
+    const parsed = JSON.parse(await readFile(resolve(root, path), 'utf8'))
+    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return null
+    const cutoff = ttl > 0 ? Date.now() - ttl : -Infinity
+    const history: DurationHistory = {}
+    for (const [key, value] of Object.entries(parsed)) {
+      const entries = observations(value)
+      if (!entries) return null
+      history[key] = entries.filter(entry => entry.recordedAt === 0 || entry.recordedAt >= cutoff)
+    }
+    return history
+  }
+  catch {
+    return null
+  }
+}
+
+export async function writeDurationHistory(root: string, path: string, history: DurationHistory, maxRuns: number): Promise<void> {
+  const serialized: Record<string, unknown> = {}
