+    const kept = [...entries].sort((a, b) => b.recordedAt - a.recordedAt).slice(0, maxRuns)
+    if (maxRuns === 1) serialized[key] = kept[0]
+    else serialized[key] = { observations: kept }
+  }
+  const target = resolve(root, path)
+  await mkdir(dirname(target), { recursive: true })
+  await writeFile(target, JSON.stringify(serialized, null, 2), 'utf8')
